```java
package com.shiftworks.jobops.service;

import com.shiftworks.jobops.config.AppProperties;
import com.shiftworks.jobops.entity.BackupRecord;
import com.shiftworks.jobops.enums.BackupStatus;
import com.shiftworks.jobops.repository.BackupRecordRepository;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.data.domain.Sort;

import java.time.Instant;
import java.util.List;
import java.util.Optional;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class BackupServiceTest {

    @Mock private BackupRecordRepository backupRecordRepository;
    @Mock private AppProperties appProperties;
    @InjectMocks private BackupService backupService;

    private BackupRecord buildRecord(BackupStatus status) {
        BackupRecord record = new BackupRecord();
        record.setId(1L);
        record.setFilename("backup-20250101-020000.sql.gz.enc");
        record.setFilePath("/backups/backup-20250101-020000.sql.gz.enc");
        record.setStatus(status);
        record.setCreatedAt(Instant.now());
        record.setExpiresAt(Instant.now().plusSeconds(30 * 86400L));
        record.setFileSize(1024L);
        record.setChecksum("abc123");
        record.setEncrypted(true);
        return record;
    }

    @Test
    void listBackupsReturnsSortedList() {
        BackupRecord r1 = buildRecord(BackupStatus.COMPLETED);
        BackupRecord r2 = buildRecord(BackupStatus.FAILED);
        r2.setId(2L);
        when(backupRecordRepository.findAll(any(Sort.class))).thenReturn(List.of(r1, r2));

        List<BackupRecord> result = backupService.listBackups();

        assertEquals(2, result.size());
        verify(backupRecordRepository).findAll(any(Sort.class));
    }

    @Test
    void restoreRejectsNonCompletedBackup() {
        BackupRecord record = buildRecord(BackupStatus.FAILED);
        when(backupRecordRepository.findById(1L)).thenReturn(Optional.of(record));

        assertThrows(IllegalStateException.class, () -> backupService.restore(1L));
    }

    @Test
    void restoreRejectsNonExistentBackup() {
        when(backupRecordRepository.findById(99L)).thenReturn(Optional.empty());

        assertThrows(IllegalArgumentException.class, () -> backupService.restore(99L));
    }
}
```

## Verification

Run: `cd backend && mvn test -pl . -Dtest=BackupServiceTest -q`

All 3 tests should pass.

# Fix: Add CsrfValidationFilter Unit Test

## Priority: MEDIUM â€” Zero test coverage for CSRF validation

## Files to create
- `backend/src/test/java/com/shiftworks/jobops/security/CsrfValidationFilterTest.java`

## Context

`CsrfValidationFilter` checks `X-XSRF-TOKEN` header on all state-changing (non-GET/HEAD/OPTIONS) requests. It skips login and register endpoints. Key testable behavior:
- GET requests pass through without CSRF check
- POST to `/api/auth/login` passes through (excluded)
- POST with valid CSRF token passes through
- POST with missing CSRF token returns 403
- POST with wrong CSRF token returns 403

## Instructions

Create `backend/src/test/java/com/shiftworks/jobops/security/CsrfValidationFilterTest.java` with this content:

```java
package com.shiftworks.jobops.security;

import com.shiftworks.jobops.entity.UserSession;
import jakarta.servlet.FilterChain;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.mock.web.MockHttpServletRequest;
import org.springframework.mock.web.MockHttpServletResponse;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.context.SecurityContextHolder;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.never;

@ExtendWith(MockitoExtension.class)
class CsrfValidationFilterTest {

    private CsrfValidationFilter filter;
    @Mock private FilterChain filterChain;

    @BeforeEach
    void setup() {
        filter = new CsrfValidationFilter();
        SecurityContextHolder.clearContext();
    }

    private UserSession buildSession(String csrfToken) {
        UserSession session = new UserSession();
        session.setCsrfToken(csrfToken);
        return session;
    }

    @Test
    void getRequestPassesThrough() throws Exception {
        MockHttpServletRequest request = new MockHttpServletRequest("GET", "/api/jobs");
        MockHttpServletResponse response = new MockHttpServletResponse();
        filter.doFilter(request, response, filterChain);
        verify(filterChain).doFilter(request, response);
    }

    @Test
    void loginPostExcludedFromCsrf() throws Exception {
        MockHttpServletRequest request = new MockHttpServletRequest("POST", "/api/auth/login");
        MockHttpServletResponse response = new MockHttpServletResponse();
        filter.doFilter(request, response, filterChain);
        verify(filterChain).doFilter(request, response);
    }

    @Test
    void postWithValidCsrfPasses() throws Exception {
        MockHttpServletRequest request = new MockHttpServletRequest("POST", "/api/jobs");
        request.addHeader("X-XSRF-TOKEN", "valid-token");
        UserSession session = buildSession("valid-token");
        request.setAttribute(SessionAuthFilter.SESSION_REQUEST_ATTRIBUTE, session);
        SecurityContextHolder.getContext().setAuthentication(
                new UsernamePasswordAuthenticationToken("user", null));
        MockHttpServletResponse response = new MockHttpServletResponse();

        filter.doFilter(request, response, filterChain);

        verify(filterChain).doFilter(request, response);
    }

    @Test
    void postWithMissingCsrfReturns403() throws Exception {
        MockHttpServletRequest request = new MockHttpServletRequest("POST", "/api/jobs");
        UserSession session = buildSession("valid-token");
        request.setAttribute(SessionAuthFilter.SESSION_REQUEST_ATTRIBUTE, session);
        SecurityContextHolder.getContext().setAuthentication(
                new UsernamePasswordAuthenticationToken("user", null));
        MockHttpServletResponse response = new MockHttpServletResponse();

        filter.doFilter(request, response, filterChain);

        assertEquals(403, response.getStatus());
        verify(filterChain, never()).doFilter(request, response);
    }

    @Test
    void postWithWrongCsrfReturns403() throws Exception {
        MockHttpServletRequest request = new MockHttpServletRequest("POST", "/api/jobs");
        request.addHeader("X-XSRF-TOKEN", "wrong-token");
        UserSession session = buildSession("valid-token");
        request.setAttribute(SessionAuthFilter.SESSION_REQUEST_ATTRIBUTE, session);
        SecurityContextHolder.getContext().setAuthentication(
                new UsernamePasswordAuthenticationToken("user", null));
        MockHttpServletResponse response = new MockHttpServletResponse();

        filter.doFilter(request, response, filterChain);

        assertEquals(403, response.getStatus());
        verify(filterChain, never()).doFilter(request, response);
    }

    @Test
    void postWithNoSessionPassesThrough() throws Exception {
        MockHttpServletRequest request = new MockHttpServletRequest("POST", "/api/jobs");
        MockHttpServletResponse response = new MockHttpServletResponse();
        filter.doFilter(request, response, filterChain);
        verify(filterChain).doFilter(request, response);
    }
}
```

## Verification

Run: `cd backend && mvn test -pl . -Dtest=CsrfValidationFilterTest -q`

All 6 tests should pass.

