# Fix: Add Missing Service Tests (RateLimitFilter, AdminUserService)

## Priority: MEDIUM â€” Critical features with zero test coverage

## Files to create
- `backend/src/test/java/com/shiftworks/jobops/security/RateLimitFilterTest.java`
- `backend/src/test/java/com/shiftworks/jobops/service/AdminUserServiceTest.java`

## Step 1 â€” Create RateLimitFilterTest.java

Create `backend/src/test/java/com/shiftworks/jobops/security/RateLimitFilterTest.java`:

```java
package com.shiftworks.jobops.security;

import com.shiftworks.jobops.config.AppProperties;
import com.shiftworks.jobops.entity.User;
import com.shiftworks.jobops.entity.UserSession;
import com.shiftworks.jobops.enums.UserRole;
import com.shiftworks.jobops.enums.UserStatus;
import com.shiftworks.jobops.service.SessionService;
import jakarta.servlet.FilterChain;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.mock.web.MockHttpServletRequest;
import org.springframework.mock.web.MockHttpServletResponse;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.verify;

@ExtendWith(MockitoExtension.class)
class RateLimitFilterTest {

    @Mock private SessionService sessionService;
    @Mock private FilterChain filterChain;
    private AppProperties appProperties;
    private RateLimitFilter filter;

    @BeforeEach
    void setup() {
        appProperties = new AppProperties();
        AppProperties.RateLimit rl = new AppProperties.RateLimit();
        rl.setPerMinute(3);
        rl.setAuthPerMinute(2);
        appProperties.setRateLimit(rl);
        filter = new RateLimitFilter(sessionService, appProperties);
    }

    @Test
    void allowsRequestsWithinLimit() throws Exception {
        MockHttpServletRequest request = new MockHttpServletRequest("POST", "/api/auth/login");
        request.setRemoteAddr("10.0.0.1");
        MockHttpServletResponse response = new MockHttpServletResponse();

        filter.doFilterInternal(request, response, filterChain);

        verify(filterChain).doFilter(request, response);
        assertEquals(200, response.getStatus());
    }

    @Test
    void blocksAuthRequestsOverIpLimit() throws Exception {
        for (int i = 0; i < 2; i++) {
            MockHttpServletRequest req = new MockHttpServletRequest("POST", "/api/auth/login");
            req.setRemoteAddr("10.0.0.2");
            filter.doFilterInternal(req, new MockHttpServletResponse(), filterChain);
        }

        MockHttpServletRequest blocked = new MockHttpServletRequest("POST", "/api/auth/login");
        blocked.setRemoteAddr("10.0.0.2");
        MockHttpServletResponse response = new MockHttpServletResponse();
        filter.doFilterInternal(blocked, response, filterChain);

        assertEquals(429, response.getStatus());
    }
}
```

## Step 2 â€” Create AdminUserServiceTest.java

Create `backend/src/test/java/com/shiftworks/jobops/service/AdminUserServiceTest.java`:

```java
package com.shiftworks.jobops.service;

import com.shiftworks.jobops.entity.User;
import com.shiftworks.jobops.enums.UserRole;
import com.shiftworks.jobops.enums.UserStatus;
import com.shiftworks.jobops.exception.BusinessException;
import com.shiftworks.jobops.repository.UserRepository;
import com.shiftworks.jobops.security.AuthenticatedUser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.http.HttpStatus;
import org.springframework.security.crypto.password.PasswordEncoder;

import java.util.Optional;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

@ExtendWith(MockitoExtension.class)
class AdminUserServiceTest {

    @Mock private UserRepository userRepository;
    @Mock private PasswordEncoder passwordEncoder;
    @Mock private AuditService auditService;
    @Mock private SessionService sessionService;
    @Mock private StepUpVerificationService stepUpVerificationService;
    @Mock private PasswordPolicyService passwordPolicyService;
    @InjectMocks private AdminUserService adminUserService;

    private AuthenticatedUser adminUser;

    @BeforeEach
    void setup() {
        adminUser = new AuthenticatedUser(1L, "admin", UserRole.ADMIN);
    }

    private User buildUser(Long id, UserRole role) {
        User user = new User();
        user.setId(id);
        user.setUsername("user" + id);
        user.setRole(role);
        user.setStatus(UserStatus.ACTIVE);
        return user;
    }

    @Test
    void cannotChangeOwnRole() {
        User self = buildUser(1L, UserRole.ADMIN);
        when(userRepository.findById(1L)).thenReturn(Optional.of(self));
        var request = new com.shiftworks.jobops.dto.AdminUserRoleChangeRequest(UserRole.EMPLOYER, "password");
        var ex = assertThrows(BusinessException.class,
                () -> adminUserService.changeRole(1L, request, adminUser));
        assertEquals(HttpStatus.BAD_REQUEST, ex.getStatus());
    }

    @Test
    void unlockLockedUser() {
        User locked = buildUser(2L, UserRole.EMPLOYER);
        locked.setStatus(UserStatus.LOCKED);
        locked.setFailedLoginAttempts(5);
        when(userRepository.findById(2L)).thenReturn(Optional.of(locked));

        adminUserService.unlock(2L);

        assertEquals(UserStatus.ACTIVE, locked.getStatus());
        assertEquals(0, locked.getFailedLoginAttempts());
        verify(userRepository).save(locked);
    }
}
```

Note: If `AdminUserService` does not have an `unlock` method with that exact signature, or the `AdminUserRoleChangeRequest` DTO has a different structure, adapt accordingly. Read the actual service file to confirm method signatures before creating the test.

## Step 3 â€” Fix test config drift in JobPostingServiceTest

Open `backend/src/test/java/com/shiftworks/jobops/service/JobPostingServiceTest.java`.

Find the `buildProps()` method. The flat pay bounds are set to `min=50` and `max=10000`, which don't match `application.yml` (which has `min=12` and `max=5000`).

Change:

```java
        flatPay.setMin(50);
        flatPay.setMax(10000);
```

To:

```java
        flatPay.setMin(12);
        flatPay.setMax(5000);
```

## Verification

Run: `cd backend && mvn compile -q` (at minimum, verify compilation)

