# Fix: Add Frontend Test Infrastructure with Vitest

## Priority: MEDIUM â€” Zero automated frontend tests exist

## Files to create
- `frontend/vitest.config.js`
- `frontend/src/__tests__/router.spec.js`
- `frontend/src/__tests__/JobPostingForm.spec.js`

## Files to modify
- `frontend/package.json`

## Step 1 â€” Add Vitest dependency

Open `frontend/package.json`.

Add to the `"devDependencies"` block:

```json
    "vitest": "^3.1.1",
    "@vue/test-utils": "^2.4.6",
    "jsdom": "^26.1.0"
```

Add to the `"scripts"` block:

```json
    "test": "vitest run",
    "test:watch": "vitest"
```

The full `"scripts"` section should look like:

```json
  "scripts": {
    "dev": "vite",
    "build": "vite build",
    "preview": "vite preview",
    "test": "vitest run",
    "test:watch": "vitest"
  },
```

## Step 2 â€” Create vitest.config.js

Create `frontend/vitest.config.js`:

```javascript
import { defineConfig } from 'vitest/config';
import vue from '@vitejs/plugin-vue';
import { fileURLToPath } from 'url';

export default defineConfig({
  plugins: [vue()],
  test: {
    environment: 'jsdom',
    globals: true
  },
  resolve: {
    alias: {
      '@': fileURLToPath(new URL('./src', import.meta.url))
    }
  }
});
```

## Step 3 â€” Create router guard test

Create `frontend/src/__tests__/router.spec.js`:

```javascript
import { describe, it, expect, vi, beforeEach } from 'vitest';

vi.mock('@/stores/auth', () => ({
  useAuthStore: vi.fn()
}));

import { useAuthStore } from '@/stores/auth';

describe('Router guard behavior', () => {
  it('redirects unauthenticated users to /login for protected routes', async () => {
    const mockStore = {
      initialized: true,
      isLoggedIn: false,
      role: null,
      restoreSession: vi.fn()
    };
    useAuthStore.mockReturnValue(mockStore);

    const { default: router } = await import('@/router/index.js');
    await router.push('/employer/dashboard');
    await router.isReady();

    expect(router.currentRoute.value.path).toBe('/login');
  });
});
```

## Step 4 â€” Create form validation test

Create `frontend/src/__tests__/JobPostingForm.spec.js`:

```javascript
import { describe, it, expect } from 'vitest';
import { computed } from 'vue';

describe('JobPostingForm pay validation', () => {
  function createPayBounds(payType) {
    return computed(() => {
      if (payType === 'HOURLY') return { min: 12, max: 75, label: 'Hourly pay must be $12â€“$75' };
      return { min: 12, max: 5000, label: 'Flat pay must be $12â€“$5,000' };
    });
  }

  it('hourly pay bounds are $12-$75', () => {
    const bounds = createPayBounds('HOURLY');
    expect(bounds.value.min).toBe(12);
    expect(bounds.value.max).toBe(75);
  });

  it('flat pay bounds are $12-$5000', () => {
    const bounds = createPayBounds('FLAT');
    expect(bounds.value.min).toBe(12);
    expect(bounds.value.max).toBe(5000);
  });

  it('hourly pay of $11 is below minimum', () => {
    const bounds = createPayBounds('HOURLY');
    expect(11 < bounds.value.min).toBe(true);
  });

  it('hourly pay of $76 is above maximum', () => {
    const bounds = createPayBounds('HOURLY');
    expect(76 > bounds.value.max).toBe(true);
  });
});
```

## Step 5 â€” Install and run

```bash
cd frontend
npm install
npm test
```

## Verification

`npm test` should show all tests passing. If the router test has import issues due to Element Plus auto-import, you may need to mock Element Plus â€” adjust accordingly.

