import { describe, it, expect } from 'vitest';
import { computed } from 'vue';

describe('JobPostingForm pay validation', () => {
  function createPayBounds(payType) {
    return computed(() => {
      if (payType === 'HOURLY') return { min: 12, max: 75, label: 'Hourly pay must be $12â€“$75' };
      return { min: 12, max: 5000, label: 'Flat pay must be $12â€“$5,000' };
    });
  }

  it('hourly pay bounds are $12-$75', () => {
    const bounds = createPayBounds('HOURLY');
    expect(bounds.value.min).toBe(12);
    expect(bounds.value.max).toBe(75);
  });

  it('flat pay bounds are $12-$5000', () => {
    const bounds = createPayBounds('FLAT');
    expect(bounds.value.min).toBe(12);
    expect(bounds.value.max).toBe(5000);
  });

  it('hourly pay of $11 is below minimum', () => {
    const bounds = createPayBounds('HOURLY');
    expect(11 < bounds.value.min).toBe(true);
  });

  it('hourly pay of $76 is above maximum', () => {
    const bounds = createPayBounds('HOURLY');
    expect(76 > bounds.value.max).toBe(true);
  });
});

