package com.shiftworks.jobops.integration;

import com.shiftworks.jobops.controller.JobPostingController;
import com.shiftworks.jobops.config.SecurityConfig;
import com.shiftworks.jobops.entity.User;
import com.shiftworks.jobops.entity.UserSession;
import com.shiftworks.jobops.enums.UserRole;
import com.shiftworks.jobops.enums.UserStatus;
import com.shiftworks.jobops.repository.JobPostingRepository;
import com.shiftworks.jobops.security.CsrfValidationFilter;
import com.shiftworks.jobops.security.RateLimitFilter;
import com.shiftworks.jobops.security.SecurityHeadersFilter;
import com.shiftworks.jobops.security.SessionAuthFilter;
import com.shiftworks.jobops.service.JobPostingService;
import com.shiftworks.jobops.service.StepUpVerificationService;
import com.shiftworks.jobops.service.SessionService;
import jakarta.servlet.http.Cookie;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.context.annotation.Import;
import org.springframework.test.web.servlet.MockMvc;

import java.time.Instant;
import java.util.Optional;

import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.post;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

@WebMvcTest(JobPostingController.class)
@Import({SecurityConfig.class, SessionAuthFilter.class, CsrfValidationFilter.class,
         RateLimitFilter.class, SecurityHeadersFilter.class})
class JobPostingSecurityTest {

    @Autowired private MockMvc mockMvc;
    @MockBean private JobPostingService jobPostingService;
    @MockBean private JobPostingRepository jobPostingRepository;
    @MockBean private StepUpVerificationService stepUpVerificationService;
    @MockBean private SessionService sessionService;

    private UserSession buildSession(UserRole role) {
        User user = new User();
        user.setId(88L);
        user.setUsername("testuser");
        user.setRole(role);
        user.setStatus(UserStatus.ACTIVE);
        user.setPasswordChangedAt(Instant.now());
        UserSession session = new UserSession();
        session.setId("test-session-token");
        session.setUser(user);
        session.setValid(true);
        session.setLastActiveAt(Instant.now());
        session.setAbsoluteExpiry(Instant.now().plusSeconds(43200));
        session.setCsrfToken("test-csrf");
        return session;
    }

    @Test
    void listJobsRequiresAuthentication() throws Exception {
        mockMvc.perform(get("/api/jobs"))
            .andExpect(status().isUnauthorized());
    }

    @Test
    void createJobRequiresEmployerRole() throws Exception {
        UserSession session = buildSession(UserRole.REVIEWER);
        when(sessionService.findValidSession(anyString())).thenReturn(Optional.of(session));

        mockMvc.perform(post("/api/jobs")
                .contentType("application/json")
                .content("{}")
                .cookie(new Cookie(SessionService.SESSION_COOKIE, "test-session-token"))
                .header("X-XSRF-TOKEN", "test-csrf"))
            .andExpect(status().isForbidden());
    }
}

content.text:
# Fix: BackupServiceTest Catch-All Masks Real Failures

## Priority: MEDIUM â€” Backup test always passes regardless of correctness

## Files to modify
- `backend/src/test/java/com/shiftworks/jobops/service/BackupServiceTest.java`

## Problem

`performBackupCreatesRecordWithCorrectFields` wraps the backup call in try/catch and asserts `e.getMessage() != null` in the catch â€” which is always true for any Java exception. The test always passes, providing zero signal.

## Instructions

Open `backend/src/test/java/com/shiftworks/jobops/service/BackupServiceTest.java`.

Replace the `performBackupCreatesRecordWithCorrectFields` test (around lines 71-89):

```java
    @Test
    void performBackupCreatesRecordWithCorrectFields() {
        AppProperties.Storage storage = new AppProperties.Storage();
        storage.setBackupPath(System.getProperty("java.io.tmpdir") + "/shiftworks-test-backups");
        when(appProperties.getStorage()).thenReturn(storage);

        try {
            BackupRecord result = backupService.performBackup();
            assertNotNull(result.getFilename());
            assertTrue(result.getFilename().startsWith("backup-"));
            assertTrue(result.getFilename().endsWith(".sql.gz.enc"));
            assertTrue(result.isEncrypted());
            assertNotNull(result.getCreatedAt());
            assertNotNull(result.getExpiresAt());
        } catch (Exception e) {
            assertTrue(e.getMessage() != null,
                "performBackup threw exception (expected in test env without mysqldump): " + e.getMessage());
        }
    }
```

With:

```java
    @Test
    void performBackupSetsRecordFieldsBeforeProcessExecution() {
        AppProperties.Storage storage = new AppProperties.Storage();
        storage.setBackupPath(System.getProperty("java.io.tmpdir") + "/shiftworks-test-backups");
        when(appProperties.getStorage()).thenReturn(storage);

        Exception thrown = assertThrows(Exception.class, () -> backupService.performBackup(),
            "Expected exception when mysqldump is not available in test environment");

        assertNotNull(thrown.getMessage());
    }

    @Test
    void performBackupRecordHasCorrectNamingConvention() {
        AppProperties.Storage storage = new AppProperties.Storage();
        storage.setBackupPath(System.getProperty("java.io.tmpdir") + "/shiftworks-test-backups");
        when(appProperties.getStorage()).thenReturn(storage);

        try {
            BackupRecord result = backupService.performBackup();
            assertTrue(result.getFilename().matches("backup-\\d{8}-\\d{6}\\.sql\\.gz\\.enc"));
            assertTrue(result.isEncrypted());
            verify(backupRecordRepository).save(any(BackupRecord.class));
        } catch (Exception e) {
            // In environments without mysqldump, verify the exception is from process execution
            assertTrue(e.getMessage().contains("mysqldump") || e.getMessage().contains("Cannot run program")
                || e.getMessage().contains("No such file") || e instanceof java.io.IOException,
                "Expected mysqldump-related failure, got: " + e.getClass().getName() + ": " + e.getMessage());
        }
    }
```

Add this import at the top if not present:
```java
import java.io.IOException;
```

Key improvements:
1. First test explicitly expects and asserts the exception rather than silently swallowing it
2. Second test validates the catch clause checks for specific, expected exception types â€” not just `!= null`

## Verification

`cd backend && mvn compile -q` â€” confirm compilation.

