content.text:
# Fix: Quarantine File Admin Review UI Missing

## Priority: LOW â€” Backend quarantine workflow has no UI

## Files to create
- `frontend/src/views/AdminQuarantineView.vue`

## Files to modify
- `frontend/src/router/index.js`
- `frontend/src/components/Sidebar.vue`

## Step 1 â€” Create AdminQuarantineView.vue

Create `frontend/src/views/AdminQuarantineView.vue`:

```vue
<script setup>
import { ref, onMounted } from 'vue';
import { getQuarantinedFiles, releaseFile, deleteFile } from '../api/files';
import { ElMessage, ElMessageBox } from 'element-plus';

const files = ref([]);
const loading = ref(false);

const fetchFiles = async () => {
  loading.value = true;
  try {
    const res = await getQuarantinedFiles();
    files.value = res.data || [];
  } finally {
    loading.value = false;
  }
};

const handleRelease = async (id) => {
  await ElMessageBox.confirm('Release this file from quarantine?', 'Confirm');
  try {
    await releaseFile(id);
    ElMessage.success('File released');
    fetchFiles();
  } catch (e) {
    ElMessage.error(e.response?.data?.message || 'Failed to release file');
  }
};

const handleDelete = async (id) => {
  await ElMessageBox.confirm('Permanently delete this quarantined file?', 'Confirm', { type: 'warning' });
  try {
    await deleteFile(id);
    ElMessage.success('File deleted');
    fetchFiles();
  } catch (e) {
    ElMessage.error(e.response?.data?.message || 'Failed to delete file');
  }
};

onMounted(fetchFiles);
</script>

<template>
  <section class="page-card">
    <h2>Quarantined Files</h2>
    <p class="muted" style="margin-bottom:16px">Files that failed validation are held here for admin review.</p>

    <el-table :data="files" v-loading="loading" stripe>
      <el-table-column prop="id" label="ID" width="70" />
      <el-table-column prop="filename" label="Filename" show-overflow-tooltip />
      <el-table-column prop="entityType" label="Entity Type" width="120" />
      <el-table-column prop="entityId" label="Entity ID" width="100" />
      <el-table-column prop="fileSize" label="Size" width="100">
        <template #default="{ row }">{{ row.fileSize ? (row.fileSize / 1024).toFixed(1) + ' KB' : 'â€”' }}</template>
      </el-table-column>
      <el-table-column prop="createdAt" label="Quarantined At" width="180" />
      <el-table-column label="Actions" width="200">
        <template #default="{ row }">
          <el-button size="small" type="success" @click="handleRelease(row.id)">Release</el-button>
          <el-button size="small" type="danger" @click="handleDelete(row.id)">Delete</el-button>
        </template>
      </el-table-column>
    </el-table>

    <el-empty v-if="!loading && files.length === 0" description="No quarantined files" />
  </section>
</template>
```

## Step 2 â€” Add route

Open `frontend/src/router/index.js`.

After the `admin-backups` route (around line 43), add:

```javascript
  { path: '/admin/quarantine', name: 'admin-quarantine', component: () => import('../views/AdminQuarantineView.vue'), meta: { requiresAuth: true, roles: ['ADMIN'] } },
```

## Step 3 â€” Add sidebar entry

Open `frontend/src/components/Sidebar.vue`.

In the `ADMIN` array inside `roleMenus`, add before the `Backups` entry:

```javascript
    { label: 'Quarantine', path: '/admin/quarantine', icon: WarningFilled },
```

## Verification

`cd frontend && npm run build` â€” confirm no build errors.

