# Fix 4 â€” Add Meaningful Frontend Tests

## Problem
Only 2 spec files exist for 29 view components. One checks a pay bound constant equals 12. The other checks one route redirect. No form submission, no validation UX, no API interaction tested.

## Files to create/modify

### 1. Create `frontend/src/__tests__/LoginView.spec.js`

Test that the login form renders required fields and validates empty submissions:

```javascript
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { mount } from '@vue/test-utils';
import { createPinia, setActivePinia } from 'pinia';

vi.mock('@/stores/auth', () => ({
  useAuthStore: () => ({
    isLoggedIn: false,
    role: null,
    login: vi.fn().mockRejectedValue(new Error('Invalid credentials')),
    restoreSession: vi.fn()
  })
}));
vi.mock('vue-router', () => ({
  useRouter: () => ({ push: vi.fn() }),
  useRoute: () => ({ query: {} })
}));

describe('LoginView', () => {
  beforeEach(() => {
    setActivePinia(createPinia());
  });

  it('renders username and password fields', async () => {
    const LoginView = (await import('@/views/LoginView.vue')).default;
    const wrapper = mount(LoginView, {
      global: {
        stubs: {
          'el-form': { template: '<form><slot/></form>' },
          'el-form-item': { template: '<div class="form-item"><slot/></div>' },
          'el-input': { template: '<input/>', props: ['modelValue'] },
          'el-button': { template: '<button><slot/></button>' },
          'el-alert': true,
          'el-card': { template: '<div><slot/></div>' }
        }
      }
    });
    const inputs = wrapper.findAll('input');
    expect(inputs.length).toBeGreaterThanOrEqual(2);
  });

  it('does not submit when fields are empty', async () => {
    const LoginView = (await import('@/views/LoginView.vue')).default;
    const wrapper = mount(LoginView, {
      global: {
        stubs: {
          'el-form': { template: '<form @submit.prevent="$emit(\'submit\')"><slot/></form>' },
          'el-form-item': { template: '<div><slot/></div>' },
          'el-input': { template: '<input/>', props: ['modelValue'] },
          'el-button': { template: '<button type="submit"><slot/></button>' },
          'el-alert': true,
          'el-card': { template: '<div><slot/></div>' }
        }
      }
    });
    expect(wrapper.vm.form.username).toBe('');
    expect(wrapper.vm.form.password).toBe('');
  });
});
```

### 2. Create `frontend/src/__tests__/Sidebar.spec.js`

Test that the sidebar renders role-appropriate menu items:

```javascript
import { describe, it, expect, vi } from 'vitest';
import { mount } from '@vue/test-utils';
import { createPinia, setActivePinia } from 'pinia';

function mountSidebarWithRole(role) {
  vi.resetModules();
  vi.doMock('@/stores/auth', () => ({
    useAuthStore: () => ({
      isLoggedIn: true,
      role: role,
      user: { id: 1, username: 'testuser' },
      logout: vi.fn()
    })
  }));
  vi.doMock('vue-router', () => ({
    useRouter: () => ({ push: vi.fn() }),
    useRoute: () => ({ path: '/' })
  }));
}

describe('Sidebar role-based menus', () => {
  it('shows employer menu items for EMPLOYER role', async () => {
    setActivePinia(createPinia());
    mountSidebarWithRole('EMPLOYER');
    const Sidebar = (await import('@/components/Sidebar.vue')).default;
    const wrapper = mount(Sidebar, {
      global: {
        plugins: [createPinia()],
        stubs: {
          'el-menu': { template: '<nav><slot/></nav>' },
          'el-menu-item': { template: '<div class="menu-item"><slot/></div>' },
          'el-sub-menu': { template: '<div class="sub-menu"><slot/></div>' },
          'el-icon': true,
          'router-link': true
        }
      }
    });
    const text = wrapper.text();
    expect(text).toContain('Dashboard');
  });

  it('shows admin menu items for ADMIN role', async () => {
    setActivePinia(createPinia());
    mountSidebarWithRole('ADMIN');
    const Sidebar = (await import('@/components/Sidebar.vue')).default;
    const wrapper = mount(Sidebar, {
      global: {
        plugins: [createPinia()],
        stubs: {
          'el-menu': { template: '<nav><slot/></nav>' },
          'el-menu-item': { template: '<div class="menu-item"><slot/></div>' },
          'el-sub-menu': { template: '<div class="sub-menu"><slot/></div>' },
          'el-icon': true,
          'router-link': true
        }
      }
    });
    const text = wrapper.text();
    expect(text).toContain('Dashboard');
  });
});
```

### 3. Create `frontend/src/__tests__/RegisterView.spec.js`

Test that the registration form enforces password complexity on the client side:

