# Fix 5d â€” Add Encryption Round-Trip Integration Test

## Problem
The AES-256-GCM column-level encryption on `contactPhone` has never been tested against a real database. No test proves that data written encrypted is read back decrypted correctly.

## Prerequisites
Apply `fix-05a` (H2 dependency) and `fix-05b` (test properties) first.

## File to create

### Create `backend/src/test/java/com/shiftworks/jobops/integration/EncryptionIT.java`

```java
package com.shiftworks.jobops.integration;

import com.shiftworks.jobops.entity.DictionaryCategory;
import com.shiftworks.jobops.entity.DictionaryLocation;
import com.shiftworks.jobops.entity.JobPosting;
import com.shiftworks.jobops.entity.User;
import com.shiftworks.jobops.enums.*;
import com.shiftworks.jobops.repository.DictionaryCategoryRepository;
import com.shiftworks.jobops.repository.DictionaryLocationRepository;
import com.shiftworks.jobops.repository.JobPostingRepository;
import com.shiftworks.jobops.repository.UserRepository;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.context.ActiveProfiles;

import java.math.BigDecimal;
import java.time.Instant;
import java.time.LocalDate;

import static org.junit.jupiter.api.Assertions.*;

@SpringBootTest
@ActiveProfiles("test")
class EncryptionIT {

    @Autowired private JobPostingRepository jobPostingRepository;
    @Autowired private UserRepository userRepository;
    @Autowired private DictionaryCategoryRepository categoryRepository;
    @Autowired private DictionaryLocationRepository locationRepository;

    @Test
    void contactPhoneIsDecryptedTransparently() {
        User employer = new User();
        employer.setUsername("enctest_" + System.currentTimeMillis());
        employer.setEmail("enctest_" + System.currentTimeMillis() + "@test.com");
        employer.setPasswordHash("$2a$10$dummy");
        employer.setRole(UserRole.EMPLOYER);
        employer.setStatus(UserStatus.ACTIVE);
        employer.setPasswordChangedAt(Instant.now());
        employer.setCreatedAt(Instant.now());
        employer.setUpdatedAt(Instant.now());
        employer = userRepository.save(employer);

        DictionaryCategory cat = new DictionaryCategory();
        cat.setName("TestCat_" + System.currentTimeMillis());
        cat.setActive(true);
        cat = categoryRepository.save(cat);

        DictionaryLocation loc = new DictionaryLocation();
        loc.setState("CA");
        loc.setCity("TestCity_" + System.currentTimeMillis());
        loc.setActive(true);
        loc = locationRepository.save(loc);

        JobPosting job = new JobPosting();
        job.setTitle("Encryption Test Job");
        job.setDescription("Testing AES-256 column encryption");
        job.setStatus(JobStatus.DRAFT);
        job.setPayType(PayType.HOURLY);
        job.setSettlementType(SettlementType.WEEKLY);
        job.setPayAmount(BigDecimal.valueOf(25));
        job.setHeadcount(5);
        job.setWeeklyHours(BigDecimal.valueOf(40));
        job.setContactPhone("2025551234");
        job.setValidityStart(LocalDate.now());
        job.setValidityEnd(LocalDate.now().plusDays(30));
        job.setEmployer(employer);
        job.setCategory(cat);
        job.setLocation(loc);
        job.setCreatedAt(Instant.now());
        job.setUpdatedAt(Instant.now());
        JobPosting saved = jobPostingRepository.save(job);

        JobPosting loaded = jobPostingRepository.findById(saved.getId()).orElseThrow();
        assertEquals("2025551234", loaded.getContactPhone(),
            "contactPhone must be decrypted transparently by JPA");
    }
}
```

This test boots the full Spring context, saves a `JobPosting` with a known `contactPhone`, reloads it from H2, and asserts the value round-trips through AES-256-GCM encryption/decryption correctly.

